import re

with open('kim-jestesmy.html', 'r', encoding='utf-8') as f:
    content = f.read()

old_section = r'<section class="about-story-section"><div class="w-layout-blockcontainer container w-container"><div class="about-story-wrapper reveal-up"><div class="about-story-title"><h2 class="main_title about-story-title-mw">Our company&#x27;s story</h2><h3 class="about-story-tag">2025@</h3></div><div class="about-story-details"><div class="about-story-description-box"><p class="about-story-description">Pycha Catering powstał z prostego założenia: doskonałe jedzenie powinno łączyć ludzi w pracy i na spotkaniach. To, co zaczęło się jako niewielka kuchnia pełna pasji, dziś jest zaufanym partnerem dla wielu firm, dostarczającym posiłki, które są równie smaczne co pożywne.</p><p class="about-story-description">Dziś jesteśmy kimś więcej niż tylko dostawcą lunchy. Kompleksowo obsługujemy spotkania biznesowe, pomagamy celebrować sukcesy i dbamy o to, by każda przerwa w pracy była chwilą wytchnienia wypełnioną pysznym jedzeniem.</p></div><div class="about-story-image img-hover-effect"><img src="assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story.png" loading="lazy" sizes="(max-width: 767px) 100vw, (max-width: 991px) 727.984375px, 908px" srcset="assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story-p-500.png 500w, assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story-p-800.png 800w, assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story.png 908w" alt="story" class="about-story-img"/></div></div></div></div></section>'

new_section = r'<section class="about-story-section"><div class="w-layout-blockcontainer container w-container"><div class="about-story-wrapper reveal-up"><div class="about-story-title"><h2 class="main_title about-story-title-mw" style="font-size: clamp(32px, 4vw, 56px);">Historia naszej firmy</h2><h3 class="about-story-tag">2025@</h3></div><div class="about-story-details"><div class="about-story-description-box"><p class="about-story-description">Pycha Catering to firma cateringowa z Sochaczewa, założona przez trzech dobrych znajomych. Powstała z pasji do dobrego jedzenia oraz przekonania, że catering firmowy może oferować nie tylko wygodę, ale przede wszystkim wysoką jakość, świeżość i doskonały smak.</p><p class="about-story-description">Naszym celem jest dostarczanie posiłków, które każdego dnia spełniają oczekiwania nawet najbardziej wymagających klientów.</p><p class="about-story-description"><strong>Czym się zajmujemy?</strong><br>Specjalizujemy się przede wszystkim w cateringu dla firm, dostarczając codzienne posiłki dla pracowników biur, zakładów produkcyjnych, magazynów oraz innych przedsiębiorstw.</p><p class="about-story-description" style="margin-bottom: 10px;">Oferujemy również catering na:</p><ul class="about-story-description" style="margin-top: 0; padding-left: 20px;"><li>imprezy firmowe,</li><li>eventy,</li><li>szkolenia i konferencje,</li><li>spotkania biznesowe,</li><li>uroczystości rodzinne i okolicznościowe.</li></ul><p class="about-story-description"><strong>Nasza filozofia</strong><br>Wierzymy, że dobre jedzenie zaczyna się od jakości składników. Nie idziemy na kompromisy – stawiamy na świeże produkty, sprawdzone receptury oraz profesjonalnych kucharzy, którzy dbają o każdy szczegół przygotowywanych dań.<br>Naszą misją jest tworzenie posiłków, które nie tylko zaspokajają głód, ale również sprawiają przyjemność i budują pozytywne doświadczenia naszych klientów.</p><p class="about-story-description" style="margin-bottom: 10px;"><strong>Co nas wyróżnia?</strong></p><ul class="about-story-description" style="margin-top: 0; padding-left: 20px;"><li>świeże i starannie wyselekcjonowane składniki,</li><li>doświadczeni kucharze,</li><li>wysoka jakość przygotowywanych dań,</li><li>punktualność dostaw,</li><li>indywidualne podejście do każdego klienta,</li><li>elastyczność i możliwość dopasowania oferty do potrzeb firmy lub wydarzenia.</li></ul><p class="about-story-description" style="margin-bottom: 10px;"><strong>Nasze wartości</strong></p><ul class="about-story-description" style="margin-top: 0; padding-left: 20px;"><li>jakość,</li><li>smak,</li><li>uczciwość,</li><li>profesjonalizm,</li><li>niezawodność,</li><li>długoterminowe relacje z klientami.</li></ul><p class="about-story-description"><strong>Hasło przewodnie:</strong> dobre jedzenie, lepszy dzień!</p></div><div class="about-story-image img-hover-effect"><img src="assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story.png" loading="lazy" sizes="(max-width: 767px) 100vw, (max-width: 991px) 727.984375px, 908px" srcset="assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story-p-500.png 500w, assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story-p-800.png 800w, assets/cdn.prod.website-files.com/68a167c0dafd6cd106a07924/68aaf8c1d8ecafb92c2c1af0_story.png 908w" alt="story" class="about-story-img"/></div></div></div></div></section>'

if old_section in content:
    new_content = content.replace(old_section, new_section)
    with open('kim-jestesmy.html', 'w', encoding='utf-8') as f:
        f.write(new_content)
    print("Replaced successfully")
else:
    print("Old section not found")
